UPDATE docs SET content = '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Deterministic performance requires avoiding the heap. In FTC, the Java Garbage Collector (GC) can trigger at any time. If it triggers during a tight control loop, your 20ms loop might balloon to 50ms or more, causing \"jitter\" in your odometry and PID controllers."}]},{"type":"paragraph","content":[{"type":"text","text":" No objects may be instantiated (using `new`) inside any method called by `OpMode.loop()` or `Command.execute()`."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"01 Why achieve zero-allocation?"}]},{"type":"paragraph","content":[{"type":"text","text":"When you create a new object, the JVM allocates memory on the "},{"type":"text","marks":[{"type":"bold"}],"text":"Heap"},{"type":"text","text":". When that object is no longer used, the "},{"type":"text","marks":[{"type":"bold"}],"text":"Garbage Collector"},{"type":"text","text":" must reclaim that memory. This process is non-deterministic and can pause your program''s execution (a \"GC Hang\"). For a robot moving at 4 m/s, a 50ms pause means moving 20cm without any control input."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"02 How to achieve zero-allocation?"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2.1 Use Pre-allocated Static Constants"}]},{"type":"paragraph","content":[{"type":"text","text":"Instead of creating new "},{"type":"text","marks":[{"type":"code"}],"text":"Pose2d"},{"type":"text","text":" or "},{"type":"text","marks":[{"type":"code"}],"text":"Rotation2d"},{"type":"text","text":" objects every tick, use static constants or pre-allocated buffers."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// BAD: Creates a new object every 20ms\nRotation2d angle = new Rotation2d(Math.toRadians(90));\n\n// GOOD: Reusable constant\nprivate static final Rotation2d NINETY_DEGREES = Rotation2d.fromDegrees(90);\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2.2 Object Pooling & Static Buffers"}]},{"type":"paragraph","content":[{"type":"text","text":"For mathematical operations, use \"Copy\" or \"Set\" methods instead of creating new results. Most geometry classes in ARESLib provide a "},{"type":"text","marks":[{"type":"code"}],"text":"set()"},{"type":"text","text":" or "},{"type":"text","marks":[{"type":"code"}],"text":"interpolation()"},{"type":"text","text":" method that modifies an existing instance."}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// BAD: Creates a new Pose2d object\nPose2d current = odometry.getPose();\nPose2d next = current.plus(transform); \n\n// GOOD: Update a pre-allocated buffer\nprivate final Pose2d poseBuffer = new Pose2d();\n\npublic void periodic() {\n    Pose2d current = odometry.getPose();\n    // Update the buffer instead of creating new ones\n    poseBuffer.set(current.getX(), current.getY(), current.getRotation());\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"2.3 Avoid List Allocations"}]},{"type":"paragraph","content":[{"type":"text","text":"Don''t use "},{"type":"text","marks":[{"type":"code"}],"text":"Stream"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"ArrayList.addAll()"},{"type":"text","text":", or any lambda that captures variables inside the hot path. These frequently trigger hidden allocations."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"03 Verification"}]},{"type":"paragraph","content":[{"type":"text","text":"To verify your code is zero-allocation, use the "},{"type":"text","marks":[{"type":"bold"}],"text":"Android Studio Profiler"},{"type":"text","text":":"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Connect to your robot via ADB."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Open the "},{"type":"text","marks":[{"type":"bold"}],"text":"Profiler"},{"type":"text","text":" tab in Android Studio."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Click on the "},{"type":"text","marks":[{"type":"bold"}],"text":"Memory"},{"type":"text","text":" timeline."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Look for \"Allocation Count.\" It should remain flat at "},{"type":"text","marks":[{"type":"bold"}],"text":"0"},{"type":"text","text":" during your OpMode''s execution."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":" Allocating objects during `init()` or `robotInit()` is perfectly fine (and required). The Zero-Allocation rule only applies to the \"Hot Path\" (code that runs repeatedly during the match)."}]}]}' WHERE slug = 'tutorials-zero-allocation';